type NullableConversationState struct {
	value *ConversationState
	isSet bool
}

func (v NullableConversationState) Get() *ConversationState {
	return v.value
}

func (v *NullableConversationState) Set(val *ConversationState) {
	v.value = val
	v.isSet = true
}

func (v NullableConversationState) IsSet() bool {
	return v.isSet
}

func (v *NullableConversationState) Unset() {
	v.value = nil
	v.isSet = false
}

func NewNullableConversationState(val *ConversationState) *NullableConversationState {
	return &NullableConversationState{value: val, isSet: true}
}

func (v NullableConversationState) MarshalJSON() ([]byte, error) {
	return json.Marshal(v.value)
}

func (v *NullableConversationState) UnmarshalJSON(src []byte) error {
	v.isSet = true
	return json.Unmarshal(src, &v.value)
}
